const raw = $json;
const stopReason = raw.stop_reason;
const text = (raw.content?.[0]?.text || '').trim();

if (!text) throw new Error('Empty response from Claude');

if (stopReason === 'max_tokens') {
  throw new Error('Claude hit the token limit — response was truncated. Increase maxTokensToSample. Response ends with: ...' + text.slice(-120));
}

const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
const clean = fenceMatch ? fenceMatch[1].trim() : text;
const start = clean.indexOf('{');
const end = clean.lastIndexOf('}');

if (start === -1 || end <= start) {
  const truncated = !clean.trimEnd().endsWith('}');
  if (truncated) throw new Error('Response appears truncated (no closing brace). Last 120 chars: ...' + clean.slice(-120));
  throw new Error('No JSON object found. Preview: ' + text.substring(0, 300));
}

const jsonStr = clean.slice(start, end + 1);

// Attempt 1: raw parse
try {
  return { json: JSON.parse(jsonStr) };
} catch (_) {}

// Attempt 2: strip // comment lines and trailing commas, then re-parse
try {
  const fixed = jsonStr
    .replace(/^\s*\/\/.*$/gm, '')
    .replace(/,(\s*[}\]])/g, '$1');
  return { json: JSON.parse(fixed) };
} catch (e2) {
  throw new Error('Parse failed after cleanup: ' + e2.message + '. Last 300 chars: ...' + jsonStr.slice(-300));
}

const ctx = $json.productContext || '';
const titleLine = ctx.match(/^TITLE:\s*(.+)$/m);
const title = titleLine ? titleLine[1].trim() : '';
// Fallback: first non-header line of markdown
const fallback = ctx.split('\n')
  .find(l => l.trim() && !l.startsWith('URL:') && !l.startsWith('TITLE:') && !l.startsWith('DESCRIPTION:') && !l.startsWith('#')) || '';
const raw = (title || fallback).replace(/[^\w\s\-]/g, ' ').replace(/\s+/g, ' ').trim();
const keyword = raw.substring(0, 60);
return [{ json: {
  productContext: $json.productContext,
  imageUrl: $json.imageUrl,
  sourceUrl: $json.sourceUrl,
  etsyKeyword: keyword
} }];

// If Firecrawl failed (continueOnFail), $json.data may be absent
const etsyMarkdown = ($json.data && $json.data.markdown) ? $json.data.markdown.substring(0, 3000) : '';
const upstream = $('Extract Keyword').item.json;
return [{ json: {
  productContext: upstream.productContext,
  imageUrl: upstream.imageUrl,
  sourceUrl: upstream.sourceUrl,
  etsySearchData: etsyMarkdown
} }];

// Email capture requests skip rate limiting entirely
if ($json.body && $json.body.emailCapture === true) {
  return [{ json: {
    emailOnly: true, blocked: false,
    email: ($json.body.email || '').slice(0, 254),
    consent: !!$json.body.consent
  } }];
}

const store = $getWorkflowStaticData('global');
const now = Date.now();
const dayMs = 24 * 60 * 60 * 1000;

// Init store
if (!store.ipData) store.ipData = {};
if (!store.global) store.global = { count: 0, reset: 0 };

// Extract IP — try Cloudflare, nginx, standard proxy headers
const h = ($json.headers || {});
const rawIp = h['cf-connecting-ip'] || h['x-real-ip'] || (h['x-forwarded-for'] || '').split(',')[0] || 'anon';
const ip = rawIp.trim().slice(0, 45);

// Reset global counter after 24h
if (now - store.global.reset > dayMs) {
  store.global = { count: 0, reset: now };
}

// Global 200/24h hard cap
if (store.global.count >= 200) {
  return [{ json: { blocked: true, code: 'global_cap' } }];
}

// Per-IP record
if (!store.ipData[ip]) store.ipData[ip] = { last: 0, count: 0, reset: 0 };
const rec = store.ipData[ip];

// Reset per-IP daily counter after 24h
if (now - rec.reset > dayMs) { rec.count = 0; rec.reset = now; }

const isFullAnalysis = !$json.body.scrapeOnly;

// 10-second cooldown only applies to full-analysis requests
// (scrapeOnly fires automatically on URL entry, right before the user fills the form)
if (isFullAnalysis && now - rec.last < 10000) {
  const wait = Math.ceil((10000 - (now - rec.last)) / 1000);
  return [{ json: { blocked: true, code: 'cooldown', wait } }];
}

// Per-IP 20 full-analysis requests per day (scrapeOnly doesn't count)
if (isFullAnalysis && rec.count >= 20) {
  return [{ json: { blocked: true, code: 'user_cap' } }];
}

// Prune stale IPs (keep store manageable — remove entries idle > 48h)
const cutoff = now - 48 * 60 * 60 * 1000;
const keys = Object.keys(store.ipData);
if (keys.length > 800) {
  for (const k of keys) { if (store.ipData[k].last < cutoff) delete store.ipData[k]; }
}

// Record the request — only track last/count for full-analysis
if (isFullAnalysis) {
  rec.last = now;
  rec.count += 1;
}
store.global.count += 1;

return [{ json: { ...$json } }];
